import {{ Injectable }} from '@nestjs/common';
import {{ MonitoringService }} from './models/monitoring.model';
import {{ MonitoringServiceRepository }} from './repositories/monitoring.repository';

@Injectable()
export class MonitoringServiceService {{
  constructor(
    private readonly repository: MonitoringServiceRepository,
  ) {{}}

  async findAll(): Promise<MonitoringService[]> {{
    return this.repository.findAll();
  }}

  async findById(id: string): Promise<MonitoringService | null> {{
    return this.repository.findById(id);
  }}

  async create(data: Partial<MonitoringService>): Promise<MonitoringService> {{
    return this.repository.create(data);
  }}

  async update(id: string, data: Partial<MonitoringService>): Promise<MonitoringService> {{
    return this.repository.update(id, data);
  }}
}}

"""
monitoring module - handles core monitoring functionality
"""
from typing import Optional, List
from dataclasses import dataclass

@dataclass
class MonitoringService:
    id: int
    name: str
    status: str = "active"
    created_at: Optional[str] = None

    def validate(self) -> bool:
        """Validate the MonitoringService instance."""
        if not self.name:
            raise ValueError("Name is required")
        return True

    def to_dict(self) -> dict:
        """Convert to dictionary representation."""
        return {{
            "id": self.id,
            "name": self.name,
            "status": self.status,
            "created_at": self.created_at
        }}
